8193	\begin{lemma}
8194	[Push--pull on a finite coproduct of legs is the product of the leg push--pulls]
8195	  \label{lem:pushPull_coprod_prod}
8196	  \lean{AlgebraicGeometry.pushPull_coprod_prod}
8197	  % NOTE: build target. The Lean declaration does not exist yet (the finite-index induction is the
8198	  % next-session unit; the prover handed off a ~6-sub-lemma decomposition — pushPullObjCongr,
8199	  % Over-X lift of sigmaOptionIso, piOptionIso, induction_empty_option with h_empty/of_equiv/h_option,
8200	  % then the specialization). Effort-break this block before the next prover round.
8201	  \uses{def:push_pull_obj, lem:isIso_modules_of_toPresheaf, lem:pushPull_binary_coprod_prod}
8202	  Let \((\mathrm{legs} : \iota \to \operatorname{Over} X)\) be a finite family of objects of
8203	  the slice category over a scheme \(X\) (\(\iota\) finite), and form the coproduct
8204	  \(\coprod_{i \in \iota} \mathrm{legs}\,i\) with structure map
8205	  \(\operatorname{Sigma.desc}(i \mapsto (\mathrm{legs}\,i).\mathrm{hom}) : \coprod_i
8206	  \mathrm{legs}\,i \to X\). Then the push--pull object on this coproduct is the product of
8207	  the per-leg push--pull objects:
8208	  \[
8209	    \operatorname{pushPullObj}\mathcal{F}\,\Bigl(\operatorname{Over.mk}\bigl(
8210	      \operatorname{Sigma.desc}(i \mapsto (\mathrm{legs}\,i).\mathrm{hom})\bigr)\Bigr)
8211	      \;\cong\;
8212	    \prod_{i \in \iota} \operatorname{pushPullObj}\mathcal{F}\,(\mathrm{legs}\,i)
8213	    \qquad \text{in } X.\mathrm{Modules}.
8214	  \]
8215	  This is the general indexed-coproduct\(\to\)product disjoint-union decomposition of a
8216	  module sheaf: the legs may have overlapping images in \(X\), but they are disjoint inside
8217	  the coproduct space \(\coprod_i \mathrm{legs}\,i\), so push--pull splits componentwise.
8218	\end{lemma}
8219	\begin{proof}
8220	  \uses{def:push_pull_obj, lem:isIso_modules_of_toPresheaf, lem:pushPull_binary_coprod_prod}
8221	  Argue by induction on the finite index type \(\iota\), iterating the binary decomposition.
8222	
8223	  \emph{Empty base.} If \(\iota\) is empty, \(\coprod_i \mathrm{legs}\,i\) is the initial scheme;
8224	  pulling \(\mathcal{F}\) back and pushing forward along the (unique) initial structure map yields the
8225	  terminal object of \(X.\mathrm{Modules}\), which is the empty product \(\prod_{i \in \emptyset}
8226	  \operatorname{pushPullObj}\mathcal{F}\,(\mathrm{legs}\,i)\). The comparison map is an isomorphism on
8227	  the underlying presheaf of abelian groups (both sides have zero sections over every open), so by
8228	  Lemma~\ref{lem:isIso_modules_of_toPresheaf} it is an isomorphism in \(X.\mathrm{Modules}\).
8229	
8230	  \emph{Inductive step.} Split off one index, writing \(\iota \simeq \{*\} \sqcup \iota'\) with
8231	  \(\iota'\) of strictly smaller cardinality. The coproduct \(\coprod_{i \in \iota} \mathrm{legs}\,i\)
8232	  reassociates as the binary coproduct of \(\mathrm{legs}\,*\) and \(\coprod_{i \in \iota'}
8233	  \mathrm{legs}\,i\), and the structure map \(\operatorname{Sigma.desc}(i \mapsto
8234	  (\mathrm{legs}\,i).\mathrm{hom})\) becomes the \(\operatorname{coprod.desc}\) of \((\mathrm{legs}
8235	  \,*).\mathrm{hom}\) and the tail structure map \(\operatorname{Sigma.desc}(i \in \iota' \mapsto
8236	  (\mathrm{legs}\,i).\mathrm{hom})\). By Lemma~\ref{lem:pushPull_binary_coprod_prod} the push--pull
8237	  object on this binary coproduct is the binary product of \(\operatorname{pushPullObj}\mathcal{F}\,
8238	  (\mathrm{legs}\,*)\) and the push--pull object on the tail coproduct
8239	  \(\operatorname{Over.mk}(\operatorname{Sigma.desc}(i \in \iota' \mapsto (\mathrm{legs}\,i).\mathrm{hom}))\);
8240	  the induction hypothesis identifies the latter with \(\prod_{i \in \iota'}
8241	  \operatorname{pushPullObj}\mathcal{F}\,(\mathrm{legs}\,i)\). Composing the binary product with the
8242	  indexed product over \(\iota'\) gives the indexed product over \(\iota\), as claimed. (All
8243	  isomorphisms produced live in \(X.\mathrm{Modules}\); where the reassociation of the coproduct is
8244	  needed it is verified through the underlying presheaf by
8245	  Lemma~\ref{lem:isIso_modules_of_toPresheaf}.)
8246	\end{proof}
